                                                                                                                    borderRadius: "1rem", 
                                                                                                                              padding: "2rem", 
                                                                                                                                        display: "flex", 
                                                                                                                                                  justifyContent: "center", 
                                                                                                                                                            alignItems: "center",
                                                                                                                                                                      border: "1px solid var(--glass-border)",
